INSERT INTO `agente_mapa_meta` VALUES (78,1,'Ascent','S','Dash sobre mid y A site permite Op plays agresivos y salida limpia.'),(79,16,'Ascent','S','Humos globales cubren mid, A main y B main desde cualquier rincón.'),(80,22,'Ascent','S','Lockdown ulti cierra A site y turret anchorea B de forma casi gratis.'),(81,8,'Ascent','S','Lineups de recon y hunter’s fury barren mid, catwalk y ambos sitios.'),(82,11,'Ascent','A','Flashes rectas de mid y knife suppression rompe setups de Killjoy/Cypher.'),(83,21,'Ascent','A','Cámara en heaven y tripwire en catwalk cubren mid y flancos.'),(84,23,'Ascent','A','Op hold en A main y tele para reposicionar frente a pushes rápidos.'),(85,3,'Ascent','A','Boombot limpia market y paint shells quiebran post-plant en ambos sitios.'),(86,19,'Ascent','A','Humos recargables y revive aguantan 1v1 tras trades en mid.'),(87,6,'Ascent','B','Slide a mid funciona, pero Jett sigue siendo mejor Op en este mapa.'),(88,4,'Ascent','B','Flash curve y wall ayudan en A main, aunque pierde frente a Jett.'),(89,9,'Ascent','B','Faults y ult útiles en A main, pero Ascent prefiere double recon.'),(90,3,'Bind','S','Boombot en hookah y satchels en teles hacen de Bind su mejor mapa.'),(91,14,'Bind','S','Tres humos simultáneos ejecutan cualquier sitio sin depender de alcance.'),(92,21,'Bind','S','Tripwires en teles A y B cubren los dos flancos más peligrosos del juego.'),(93,15,'Bind','A','Muro parte A short y molly post-plant imparable en B site.'),(94,11,'Bind','A','Flash y suppression desactivan Cypher/Viper en ejecutes a sitio.'),(95,10,'Bind','A','Perro de info y flashes largas rompen hookah y showers.'),(96,12,'Bind','A','Prowlers localizan en pasillos cerrados y haunt revela post-humo.'),(97,13,'Bind','A','Wingman plantea y Dizzy dispara flashes en ejecutes cortos.'),(98,4,'Bind','B','Flash curve y wall ayudan a tradear en hookah, pero carece de movilidad.'),(99,1,'Bind','B','Dash viable en A short, pero Raze domina los ejecutes cerrados.'),(100,22,'Bind','B','Trampas funcionan en B site, aunque Cypher cubre mejor los teles.'),(101,16,'Haven','S','Humos globales cubren tres sitios con rotaciones lentas, tele decisivo.'),(102,8,'Haven','S','Dart revela A long, C long y garage con un solo recon bolt.'),(103,1,'Haven','S','Dash para tomar A long u Op hold en C long sin riesgo de reposición.'),(104,19,'Haven','S','Humos recargables y revive salvan sitios mientras el equipo rota.'),(105,21,'Haven','A','Cam en garage y tripwires cubren los flancos largos de tres sitios.'),(106,22,'Haven','A','Anchor sólido en C long; ult cierra A site para retakes de 3.'),(107,9,'Haven','A','Faults y stuns abren C long y A short en pasillos estrechos.'),(108,12,'Haven','A','Haunt y prowlers limpian tres sitios y cubren rotaciones lentas.'),(109,10,'Haven','A','Flashes y perro de info ejecutan A short y C long con trades fáciles.'),(110,3,'Haven','B','Nades útiles en A short, pero Jett aprovecha mejor la Op.'),(111,17,'Haven','B','Control global viable, aunque Omen y Clove dan más impacto individual.'),(112,11,'Haven','B','Supresión molesta al Cypher defensor, roster ya saturado de iniciadores.'),(113,15,'Breeze','S','Muro gigante parte A cave y mid, molly decay fija post-plants.'),(114,1,'Breeze','S','Dash y updraft crean Op holds agresivos en ángulos larguísimos.'),(115,23,'Breeze','S','Op estable a larga distancia y tele de emergencia ante flanks.'),(116,8,'Breeze','S','Dart cubre A cave, mid doors y B site desde un único pixel.'),(117,21,'Breeze','A','Tripwires en tubos de A y mid cortan los dos flancos principales.'),(118,18,'Breeze','A','Muros de agua complementan a Viper y tapan angulos en ejecute de A.'),(119,10,'Breeze','A','Perro de info y heal crítico en un mapa con trades lentos.'),(120,11,'Breeze','A','Knife supresión rompe a Viper y Cypher en ejecutes largos.'),(121,13,'Breeze','B','Wingman plantea en site abierto, pero Sova recon es superior.'),(122,6,'Breeze','B','Velocidad para rotar, aunque Jett y Raze son mejores duelists aquí.'),(123,3,'Breeze','B','Satchels cubren mucho terreno, pero no gana los duelos de Op.'),(124,15,'Icebox','S','Muro vertical y molly indispensables por la verticalidad del mapa.'),(125,8,'Icebox','S','Recon dart y hunter’s fury dominan mid y B site abiertos.'),(126,20,'Icebox','S','Muro eleva a nest y corta B kitchen, wall clutch post-plant en A.'),(127,1,'Icebox','S','Updraft+dash suben a yellow y nest para Op holds imposibles de replicar.'),(128,22,'Icebox','A','Turret y trampas blindan B site, ult fuerza el defuse en retakes.'),(129,23,'Icebox','A','Op hold en B tubes y tele para rotar entre mid y screens.'),(130,18,'Icebox','A','Muros extensos cubren A site abierto cuando Viper se gasta.'),(131,10,'Icebox','A','Heal y flashes compensan trades lentos en un mapa con Op pesado.'),(132,21,'Icebox','B','Tripwires viables en B kitchen, Killjoy rinde mejor en sitios abiertos.'),(133,12,'Icebox','B','Prowlers ayudan en mid, pero Sova sigue siendo el iniciador top.'),(134,3,'Icebox','B','Satchels para subir a yellow decentes, Jett domina los Op holds.'),(135,3,'Split','S','Boombot y nades devastan pasillos cerrados, satchel sube a A ramps.'),(136,16,'Split','S','Humos precisos en mid y ambos sitios, tele flanquea por vents.'),(137,20,'Split','S','Muro corta mid y ralentiza pushes, slow orbs cubren rotaciones cortas.'),(138,21,'Split','S','Cam en mid y tripwires en vents anulan flancos constantes.'),(139,9,'Split','A','Stuns y aftershock rompen defensas en A main y B mail.'),(140,10,'Split','A','Flashes curvas perfectas para A main, heal tras entradas brutales.'),(141,14,'Split','A','Humos simultáneos y molly ejecutan sitios pequeños sin problema.'),(142,12,'Split','A','Prowlers limpian mid mail y heaven, haunt revela anchors.'),(143,6,'Split','A','Slide por mid rompe el timing de los defensores en A main.'),(144,1,'Split','B','Dash a A ramps viable, pero Raze saca más valor de los espacios cerrados.'),(145,22,'Split','B','Setup en B site sólido, Cypher cubre mejor los flancos de vents.'),(146,3,'Lotus','S','Granadas rebotan en C hall y A main estrechos, boombot limpia waterfall.'),(147,15,'Lotus','S','Muro dobla defensa de A site y molly corta C mound en post-plant.'),(148,22,'Lotus','S','Ult cierra sitio en retake de 3 sites y trampas blindan C link.'),(149,16,'Lotus','A','Humos globales y tele rotan entre tres sitios con puertas rotatorias.'),(150,12,'Lotus','A','Haunt revela detrás de puertas giratorias y prowlers ciegan ejecutes.'),(151,10,'Lotus','A','Flashes y perro de info críticos para tres sitios con trades lentos.'),(152,9,'Lotus','A','Stuns y faults rompen defensas en A main y C hall estrechos.'),(153,18,'Lotus','A','Segundo controller viable, muros cubren ejecute C y A link.'),(154,1,'Lotus','A','Dash de A main para Op agresiva, updraft a pillars clutch.'),(155,11,'Lotus','B','Knife suppression rompe Killjoy/Viper, pero compite con Fade y Skye.'),(156,21,'Lotus','B','Cam en C mound y tripwires en tree, Killjoy suele ganar el slot.'),(157,9,'Fracture','S','Mapa lineal diseñado para faults y stuns, must-pick absoluto.'),(158,3,'Fracture','S','Satchels a dish y A site, nades en pasillos estrechos de ambos lados.'),(159,6,'Fracture','S','Slide por zipline acelera entries y rotaciones H-spawn en segundos.'),(160,14,'Fracture','A','Humos rápidos y molly ejecutan A dish y B arcade sin exceso de rango.'),(161,12,'Fracture','A','Haunt y prowlers barren A dish y B site; ult limpia post-humo.'),(162,8,'Fracture','A','Darts de arcade y dish revelan anchors pese a la geometría torcida.'),(163,22,'Fracture','A','Ult fuerza el defuse en sitios pequeños, turret cierra B arcade.'),(164,19,'Fracture','A','Humos recargables y revive mantienen presencia en sitios pequeños.'),(165,23,'Fracture','B','Op hold en A main con tele de escape, pero el kit sufre fuera del site.'),(166,21,'Fracture','B','Tripwires en ziplines útiles, Killjoy saca más valor en sitios chicos.'),(167,15,'Fracture','B','Molly post-plant viable, Brim y Omen rinden más en rotaciones cortas.'),(168,17,'Pearl','S','Estrellas globales sin tele propia del mapa: controla mid y site a la vez.'),(169,23,'Pearl','S','Op hold en mid y connector, tele cubre la ausencia de rotaciones rápidas.'),(170,12,'Pearl','S','Prowlers y haunt esenciales en mid cerrado con muchos rincones.'),(171,18,'Pearl','A','Muros de agua cubren ejecutes largos de A main y B link.'),(172,1,'Pearl','A','Dash para entries en A main y B link, updraft a pocket.'),(173,6,'Pearl','A','Slide por mid rompe Chamber y crea entries rápidas a site.'),(174,3,'Pearl','A','Nades en dugout y B site, satchels para subir a pocket y heaven.'),(175,21,'Pearl','A','Cam en mid y trips en A dugout neutralizan flancos constantes.'),(176,24,'Pearl','A','Sensor y wall retrasan flancos por mid y ganan tiempo de rotación.'),(177,19,'Pearl','B','Humos recargables útiles, Astra sigue siendo el controlador rey aquí.'),(178,15,'Pearl','B','Muro en A main viable, Harbor cubre mejor las rotaciones cortas.'),(179,16,'Sunset','S','Humos globales cubren A main, mid y B market; tele a elevados clutch.'),(180,21,'Sunset','S','Cam en market y tripwires en A alley: pareja casi 100% pick en pro.'),(181,3,'Sunset','S','Boombot en A main y satchel a B market devastan el mapa corto.'),(182,14,'Sunset','A','Alcance limitado deja de ser problema: humos y molly ejecutan cualquier site.'),(183,4,'Sunset','A','Flash curve en mid y wall en A main sostienen entries repetidos.'),(184,12,'Sunset','A','Prowlers y haunt limpian mid top y B market cerrado.'),(185,1,'Sunset','A','Dash por A main y mid para Op holds con salida rápida.'),(186,19,'Sunset','A','Humos recargables y revive alargan defensa en sitios compactos.'),(187,8,'Sunset','A','Darts de mid top y A main revelan anchors en un mid muy disputado.'),(188,22,'Sunset','B','Ult en B market sólido, pero Cypher cubre mejor los flancos largos.'),(189,9,'Sunset','B','Faults y stuns quiebran mid, compite con Fade por el slot iniciador.'),(190,22,'Abyss','S','Turret y trampas cerca de huecos empujan enemigos al vacío.'),(191,19,'Abyss','S','Humos recargables y revive aguantan rotaciones larguísimas.'),(192,17,'Abyss','S','Gravity well arrastra enemigos hacia el abismo; estrellas cubren todo el mapa.'),(193,1,'Abyss','A','Updraft asegura Op holds en A main y B main sin miedo al fall damage.'),(194,8,'Abyss','A','Recon bolt atraviesa los techos abiertos y cubre sitios vastos.'),(195,21,'Abyss','A','Tripwires en bordes detectan pushes y empujan al vacío a los descuidados.'),(196,4,'Abyss','A','Wall sobre el vacío bloquea ángulos y heal sostiene entradas largas.'),(197,25,'Abyss','A','Razorvine en bordes y trampas de arma cubren sitios con poca cobertura.'),(198,16,'Abyss','A','Humos rápidos y tele agresivo sobre elevaciones frente al abismo.'),(199,9,'Abyss','B','Faults útiles, pero la falta de paredes completas reduce su alcance.'),(200,3,'Abyss','B','Boombot viable en bordes, pero pierde en rotaciones muy largas.');
