/*!40000 ALTER TABLE `entrenamiento_opcion` DISABLE KEYS */;
INSERT INTO `entrenamiento_opcion` VALUES (1,'Iron','aim','Colocación de mira en esquinas (Iron)','Practica apuntar siempre a la altura de la cabeza en cada esquina antes de asomar. Mapa: The Range o Aim Labs. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(2,'Iron','aim','Flick shots a la cabeza (Iron)','Calienta con 3 tandas de flicks rápidos en Aim Labs (Gridshot Precision). Céntrate en detenerte en la diana, no pasarte. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(3,'Iron','aim','Tracking contra objetivos móviles (Iron)','Sigue a bots moviéndose horizontalmente sin disparar durante 5 min, luego añade ráfagas cortas. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(4,'Iron','aim','Microajustes tras strafear (Iron)','Entra al Range, corre 2 pasos, para en seco y dispara. Repite 100 veces. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(5,'Iron','aim','Transiciones entre enemigos (Iron)','Coloca 2 bots separados, alterna headshots. Objetivo: bajar el tiempo entre kills. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(6,'Iron','aim','Pre-aim en ángulos comunes (Iron)','Camina por el mapa apuntando a posiciones típicas antes de verlas (ej: window en Ascent, door en Bind). Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(7,'Iron','aim','Control de mira en swings (Iron)','Haz wide swings a bots quietos manteniendo la mira a la altura de la cabeza durante todo el movimiento. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(8,'Iron','aim','Reset post-kill (Iron)','Tras cada kill, corrige la mira al siguiente ángulo sin pausa. Entrena con 4 bots en línea. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(9,'Iron','movilidad','Counter-strafe limpio (Iron)','Pulsa la tecla contraria a la dirección en la que corres antes de disparar. Precisión sube 50% si lo haces bien. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(10,'Iron','movilidad','Jiggle peek rápido (Iron)','Asomarte y volver a cubrirte en menos de 0.3 s para sacar info sin morir. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(11,'Iron','movilidad','Wide swing vs close swing (Iron)','Decide según el ángulo: wide para Operator, close para angles cerrados. Practica ambos 10 min. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(12,'Iron','movilidad','Strafing durante el tiroteo (Iron)','Mueve A-D-A-D combinando con counter-strafe. No dispares en movimiento continuo. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(13,'Iron','movilidad','Movimiento silencioso (Iron)','Alterna andar (shift) y correr. Los pasos dan info al enemigo: úsalo a tu favor con fakes. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(14,'Iron','movilidad','Uso de dash o habilidad de movimiento (Iron)','Para agentes con dash (Jett, Neon, Raze): practica entries con dash + disparo justo al aterrizar. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(15,'Iron','movilidad','Rotaciones rápidas entre sitios (Iron)','Cronometra tus rotaciones mid-to-A y mid-to-B. Meta: menos de 12 segundos. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(16,'Iron','movilidad','Posicionamiento sin chocar con aliados (Iron)','En Range con 4 aliados simulados, encuentra ángulos que no estorben crossfire. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(17,'Iron','disparo','Ráfagas cortas a media distancia (Iron)','Phantom/Vandal en ráfagas de 3 balas a 15-25 metros. Precisión objetivo: 60%+. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(18,'Iron','disparo','Disparo a dos toques a larga distancia (Iron)','Tap-tap a 30+ metros esperando 0.3 s entre disparos para reset de spread. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(19,'Iron','disparo','Control de spray del Vandal (Iron)','Vacía cargador completo en pared, memoriza el patrón. Compensa arrastrando hacia abajo-izquierda. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(20,'Iron','disparo','Control de spray del Phantom (Iron)','Igual que Vandal pero con pattern propio, más fácil de controlar. 30 repeticiones. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(21,'Iron','disparo','Headshots con pistolas (Iron)','Ghost y Sheriff: 10 minutos de deathmatch sólo pistolas, solo headshots. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(22,'Iron','disparo','Apertura con Operator (Iron)','Hold estático en ángulo largo, 1 disparo y reposicionar. No holdear dos veces el mismo ángulo. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(23,'Iron','disparo','Tapping a larga distancia (Iron)','Dispara 1 bala, espera a que la mira reset, vuelve a disparar. Fundamental en 1v1 a larga. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(24,'Iron','disparo','Economía: eco, pistola y full-buy (Iron)','Estudia las 3 situaciones: cuándo ahorrar, cuándo forzar y cuándo full-buy según ronda. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(25,'Iron','utilidad','Humos básicos de controlador (Iron)','Aprende 3 humos default por sitio con tu controller principal (Omen, Brimstone o Viper). Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(26,'Iron','utilidad','Flashes pop en esquinas (Iron)','Flash curveada justo tras la esquina para cegar sin mostrarte. Practica con KAY/O, Skye o Phoenix. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(27,'Iron','utilidad','Recon darts seguros (Iron)','Con Sova o Fade: lanza recon desde cover sin exponerte. Aprende 2 lineups por mapa. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(28,'Iron','utilidad','Molly post-plant (Iron)','Molly que cubre la spike tras plant. Evita desactivaciones silenciosas. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(29,'Iron','utilidad','Utilidad defensiva en sitio (Iron)','Sage wall y Killjoy turret: aprende posiciones que retrasan un push completo 10+ segundos. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(30,'Iron','utilidad','Sincronización de utilidad en equipo (Iron)','Flash + entry al mismo tiempo. Cuenta en voz alta \"3-2-1 flash\" antes de lanzar. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(31,'Iron','utilidad','Gestión de ultimate (Iron)','No gastes ult en ronda ganada. Aprende valor económico de cada ult (Judgment, Showstopper, etc). Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(32,'Iron','utilidad','Fakes con utilidad (Iron)','Utiliza humos y flashes en sitio B para forzar rotación enemiga, luego ejecuta A. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(33,'Iron','game_sense','Callouts básicos del mapa (Iron)','Aprende los 15 callouts principales de cada mapa. Sin callouts claros no hay coordinación. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(34,'Iron','game_sense','Timings de rotación (Iron)','Cronometra cuánto tarda el enemigo en llegar desde mid a tu sitio. Úsalo para decidir rotaciones. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(35,'Iron','game_sense','Lectura del audio enemigo (Iron)','Dedica 5 min de partida con volumen alto a IDENTIFICAR sonidos (pasos, reloads, utility). Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(36,'Iron','game_sense','Decisiones de plant o default (Iron)','Con tiempo >30s y sitio libre: default. Con presión: plant inmediato y post-plant. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(37,'Iron','game_sense','Clutch 1vX (Iron)','Separa enemigos, usa utilidad para aislar uno y obliga duelos 1v1 secuenciales. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(38,'Iron','game_sense','Info post-kill (Iron)','Tras un kill, revela a tu equipo: \"one down A main, low HP\". Nunca mates en silencio. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(39,'Iron','game_sense','Lectura de la economía enemiga (Iron)','Cuenta armas y ulti enemigas. Si van eco, juega seguro. Si full-buy, anti-eco no aplica. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(40,'Iron','game_sense','Adaptación al meta del oponente (Iron)','Si el enemigo repite la misma estrategia 2 rondas, cambia tu setup defensivo para contrarrestar. Adaptación Iron: Enfoque en lo básico: repetición lenta y correcta, sin presión de tiempo. Duración recomendada: 20 min.',NULL),(41,'Bronze','aim','Colocación de mira en esquinas (Bronze)','Practica apuntar siempre a la altura de la cabeza en cada esquina antes de asomar. Mapa: The Range o Aim Labs. Adaptación Bronze: Sube ligeramente la velocidad y alterna objetivos estáticos y uno en movimiento. Duración recomendada: 25 min.',NULL),(42,'Bronze','aim','Flick shots a la cabeza (Bronze)','Calienta con 3 tandas de flicks rápidos en Aim Labs (Gridshot Precision). Céntrate en detenerte en la diana, no pasarte. Adaptación Bronze: Sube ligeramente la velocidad y alterna objetivos estáticos y uno en movimiento. Duración recomendada: 25 min.',NULL),(43,'Bronze','aim','Tracking contra objetivos móviles (Bronze)','Sigue a bots moviéndose horizontalmente sin disparar durante 5 min, luego añade ráfagas cortas. Adaptación Bronze: Sube ligeramente la velocidad y alterna objetivos estáticos y uno en movimiento. Duración recomendada: 25 min.',NULL),(44,'Bronze','aim','Microaju