CREATE TABLE `entrenamiento_video` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `rango` enum('Iron','Bronze','Silver','Gold','Platinum','Diamond','Ascendant','Immortal','Radiant') NOT NULL,
  `categoria` enum('aim','movilidad','disparo','utilidad','game_sense') NOT NULL,
  `titulo` varchar(150) NOT NULL,
  `video_url` varchar(255) NOT NULL,
  `descripcion` varchar(300) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_rango_categoria` (`rango`,`categoria`),
  KEY `idx_video_rango` (`rango`)
) ENGINE=InnoDB AUTO_INCREMENT=46 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
